/** @module sso-provider-edit */

'use client';

import { getComponentStyles } from '@auth0/universal-components-core';
import { useState, useMemo } from 'react';

import { SsoDomainTab } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-edit/sso-domain-tab';
import { SsoProviderTab } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-edit/sso-provider-tab';
import { SsoProvisioningTab } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-edit/sso-provisioning/sso-provisioning-tab';
import { Header } from '@/components/auth0/shared/header';
import { StyledScope } from '@/components/auth0/shared/styled-scope';
import { Spinner } from '@/components/ui/spinner';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { useSsoProviderEdit } from '@/hooks/my-organization/use-sso-provider-edit';
import { useSsoProviderEditLogic } from '@/hooks/my-organization/use-sso-provider-edit-logic';
import { useTheme } from '@/hooks/shared/use-theme';
import { useTranslator } from '@/hooks/shared/use-translator';
import { cn } from '@/lib/utils';
import type {
  SsoProviderEditHandlerProps,
  SsoProviderEditLogicProps,
  SsoProviderEditProps,
  SsoProviderEditViewProps,
} from '@/types/my-organization/idp-management/sso-provider/sso-provider-edit-types';

/**
 * Internal SSO provider edit container(logic) component.
 * @param props - Component props
 * @param props.providerId - ID of the SSO provider
 * @param props.backButton - Configuration for the back button
 * @param props.sso - SSO configuration
 * @param props.provisioning - Provisioning configuration
 * @param props.domains - Array of domains
 * @param props.hideHeader - Whether to hide the header
 * @param props.customMessages - Custom translation messages to override defaults
 * @param props.styling - Custom styling configuration with variables and classes
 * @param props.schema - Zod validation schema
 * @param props.readOnly - Whether the component is in read-only mode
 * @internal
 * @returns JSX element
 */
function SsoProviderEditContainer(props: SsoProviderEditProps) {
  const {
    providerId,
    backButton,
    sso,
    provisioning,
    domains,
    hideHeader = false,
    customMessages = {},
    styling = {
      variables: { common: {}, light: {}, dark: {} },
      classes: {},
    },
    schema,
    readOnly = false,
  } = props;

  const ssoProviderEdit = useSsoProviderEdit(providerId, {
    sso,
    provisioning,
    domains,
    customMessages,
  });

  const ssoProviderEditLogic = useSsoProviderEditLogic(ssoProviderEdit);

  const ssoProviderCreateLogicProps: Omit<SsoProviderEditLogicProps, 'handleToggleProvider'> = {
    ...ssoProviderEdit,
    shouldAllowDeletion: ssoProviderEditLogic.shouldAllowDeletion,
    isLoadingConfig: ssoProviderEditLogic.isLoadingConfig,
    idpConfig: ssoProviderEditLogic.idpConfig,
    isLoadingIdpConfig: ssoProviderEditLogic.isLoadingIdpConfig,
    showProvisioningTab: ssoProviderEditLogic.showProvisioningTab,
    styling,
    customMessages,
    backButton,
    schema,
    readOnly,
    providerId,
    domains,
    hideHeader,
  };

  const ssoProviderCreateHandlerProps: SsoProviderEditHandlerProps = {
    handleToggleProvider: ssoProviderEditLogic.handleToggleProvider,
    updateProvider: ssoProviderEdit.updateProvider,
    listScimTokens: ssoProviderEdit.listScimTokens,
    syncSsoAttributes: ssoProviderEdit.syncSsoAttributes,
    onDeleteConfirm: ssoProviderEdit.onDeleteConfirm,
    onRemoveConfirm: ssoProviderEdit.onRemoveConfirm,
    createScimTokenAction: ssoProviderEdit.createScimToken,
    deleteScimTokenAction: ssoProviderEdit.deleteScimToken,
    createProvisioningAction: ssoProviderEdit.createProvisioning,
    deleteProvisioningAction: ssoProviderEdit.deleteProvisioning,
    syncProvisioningAttributes: ssoProviderEdit.syncProvisioningAttributes,
  };

  return (
    <SsoProviderEditView
      logic={ssoProviderCreateLogicProps}
      handlers={ssoProviderCreateHandlerProps}
    />
  );
}

/**
 * Internal SSO provider edition view component
 * @param props - Component props
 * @param props.logic - Component logic props
 * @param props.handlers - Component handler props
 * @internal
 * @returns JSX element
 */
function SsoProviderEditView({ logic, handlers }: SsoProviderEditViewProps) {
  const {
    styling,
    schema,
    readOnly,
    providerId,
    domains,
    hideHeader,
    provider,
    organization,
    isLoading,
    isUpdating,
    isDeleting,
    isRemoving,
    idpConfig,
    customMessages,
    backButton,
    shouldAllowDeletion,
    isLoadingConfig,
    isLoadingIdpConfig,
    showProvisioningTab,
    isProvisioningUpdating,
    isProvisioningDeleting,
    isScimTokensLoading,
    isScimTokenCreating,
    isScimTokenDeleting,
    isSsoAttributesSyncing,
    isProvisioningAttributesSyncing,
    hasSsoAttributeSyncWarning,
    hasProvisioningAttributeSyncWarning,
  } = logic;

  const {
    updateProvider,
    listScimTokens,
    syncSsoAttributes,
    onDeleteConfirm,
    onRemoveConfirm,
    handleToggleProvider,
    createProvisioningAction,
    deleteProvisioningAction,
    createScimTokenAction,
    deleteScimTokenAction,
    syncProvisioningAttributes,
  } = handlers;

  const { isDarkMode } = useTheme();
  const [activeTab, setActiveTab] = useState('sso');
  const { t } = useTranslator('idp_management.edit_sso_provider', customMessages);
  const currentStyles = useMemo(
    () => getComponentStyles(styling, isDarkMode),
    [styling, isDarkMode],
  );

  if (isLoading || isLoadingConfig || isLoadingIdpConfig) {
    return (
      <div className="flex justify-center items-center p-8">
        <Spinner />
      </div>
    );
  }

  return (
    <StyledScope style={currentStyles.variables}>
      <div className="w-full">
        {!hideHeader && (
          <Header
            title={provider?.display_name || provider?.name || ''}
            backButton={
              backButton && {
                ...backButton,
                text: t('header.back_button_text'),
              }
            }
            isLoading={isUpdating}
            actions={[
              {
                type: 'switch',
                checked: provider?.is_enabled ?? false,
                onCheckedChange: handleToggleProvider,
                disabled: isUpdating,
                tooltip: {
                  content: provider?.is_enabled
                    ? t('header.disable_provider_tooltip_text')
                    : t('header.enable_provider_tooltip_text'),
                },
              },
            ]}
            className={currentStyles?.classes?.['SsoProviderEdit-header']}
          />
        )}

        <Tabs
          value={activeTab}
          onValueChange={setActiveTab}
          className={cn('space-y-10', currentStyles?.classes?.['SsoProviderEdit-tabs'])}
        >
          <TabsList
            className={cn('grid w-full', showProvisioningTab ? 'grid-cols-3' : 'grid-cols-2')}
          >
            <TabsTrigger value="sso" className="text-sm">
              {t('tabs.sso.name')}
            </TabsTrigger>
            {showProvisioningTab && (
              <TabsTrigger value="provisioning" className="text-sm">
                {t('tabs.provisioning.name')}
              </TabsTrigger>
            )}
            <TabsTrigger value="domain" className="text-sm">
              {t('tabs.domains.name')}
            </TabsTrigger>
          </TabsList>

          <TabsContent value="sso">
            <SsoProviderTab
              provider={provider}
              organization={organization}
              onDelete={onDeleteConfirm}
              onRemove={onRemoveConfirm}
              isDeleting={isDeleting}
              isRemoving={isRemoving}
              idpConfig={idpConfig}
              shouldAllowDeletion={shouldAllowDeletion}
              hasSsoAttributeSyncWarning={hasSsoAttributeSyncWarning}
              onAttributeSync={syncSsoAttributes}
              isSyncingAttributes={isSsoAttributesSyncing}
              customMessages={customMessages?.tabs?.sso?.content}
              styling={styling}
              formActions={{
                isLoading: isUpdating,
                nextAction: {
                  disabled: isUpdating || !provider || isLoading,
                  onClick: updateProvider,
                },
              }}
              readOnly={readOnly}
            />
          </TabsContent>

          {showProvisioningTab && (
            <TabsContent value="provisioning">
              <SsoProvisioningTab
                provider={provider!}
                isProvisioningUpdating={isProvisioningUpdating}
                isProvisioningDeleting={isProvisioningDeleting}
                isScimTokensLoading={isScimTokensLoading}
                isScimTokenCreating={isScimTokenCreating}
                isScimTokenDeleting={isScimTokenDeleting}
                hasProvisioningAttributeSyncWarning={hasProvisioningAttributeSyncWarning}
                onAttributeSync={syncProvisioningAttributes}
                isSyncingAttributes={isProvisioningAttributesSyncing}
                onCreateProvisioning={createProvisioningAction}
                onDeleteProvisioning={deleteProvisioningAction}
                onListScimTokens={listScimTokens}
                onCreateScimToken={createScimTokenAction}
                onDeleteScimToken={deleteScimTokenAction}
                customMessages={customMessages?.tabs?.provisioning?.content}
                styling={styling}
              />
            </TabsContent>
          )}

          <TabsContent value="domain">
            <SsoDomainTab
              customMessages={customMessages?.tabs?.domains?.content}
              styling={styling}
              domains={domains}
              schema={schema?.domains}
              idpId={providerId}
              provider={provider}
              readOnly={readOnly}
            />
          </TabsContent>
        </Tabs>
      </div>
    </StyledScope>
  );
}

/**
 * SSO provider edit interface with tabbed navigation.
 *
 * Provides a complete interface for editing SSO provider settings including:
 * - SSO tab: Provider configuration, attribute mappings, delete/remove actions
 * - Provisioning tab: SCIM configuration and token management
 * - Domains tab: Domain association and verification
 *
 * @param props - {@link SsoProviderEditProps}
 * @param props.providerId - Identity provider ID to edit
 * @param props.backButton - Back button configuration
 * @param props.sso - SSO tab lifecycle hooks (save, delete, remove actions)
 * @param props.provisioning - Provisioning tab lifecycle hooks
 * @param props.domains - Domains tab configuration
 * @param props.hideHeader - Hide the header section
 * @param props.customMessages - Custom i18n message overrides
 * @param props.styling - CSS variables and class overrides
 * @param props.schema - Validation schema overrides
 * @param props.readOnly - Render in read-only mode
 * @returns SSO provider edit component
 *
 * @see {@link SsoProviderEditProps} for full props documentation
 *
 * @example
 * ```tsx
 * <SsoProviderEdit
 *   providerId="con_abc123"
 *   sso={{
 *     saveAction: { onAfter: (provider) => console.log('Saved:', provider) },
 *     deleteAction: { onAfter: () => navigate('/providers') },
 *   }}
 *   backButton={{
 *     onClick: () => navigate('/providers'),
 *   }}
 * />
 * ```
 */
const SsoProviderEdit = SsoProviderEditContainer;

export { SsoProviderEdit, SsoProviderEditView };

/**
 * Domain creation modal.
 * @module domain-create-modal
 * @internal
 */

import {
  createDomainCreateSchema,
  type InternalDomainCreateFormValues,
} from '@auth0/universal-components-core';
import { zodResolver } from '@hookform/resolvers/zod';
import * as React from 'react';
import { useForm } from 'react-hook-form';

import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormMessage,
  FormLabel,
} from '@/components/ui/form';
import { Modal } from '@/components/ui/modal';
import { TextField } from '@/components/ui/text-field';
import { useTranslator } from '@/hooks/shared/use-translator';
import { cn } from '@/lib/utils';
import type { DomainCreateModalProps } from '@/types/my-organization/domain-management/domain-create-types';

/**
 *
 * @param props - Component props.
 * @param props.translatorKey - Translation namespace key
 * @param props.className - Optional CSS class name for styling
 * @param props.customMessages - Custom translation messages to override defaults
 * @param props.isOpen - Whether the modal/dialog is open
 * @param props.isLoading - Whether the component is in a loading state
 * @param props.schema - Zod validation schema
 * @param props.onClose - Callback fired when the component should close
 * @param props.onCreate - Callback fired when create action is triggered
 * @returns JSX element
 */
export function DomainCreateModal({
  translatorKey = 'domain_management.domain_create.modal',
  className,
  customMessages,
  isOpen,
  isLoading,
  schema,
  onClose,
  onCreate,
}: DomainCreateModalProps) {
  const { t } = useTranslator(translatorKey, customMessages);

  const domainCreateSchema = React.useMemo(
    () => createDomainCreateSchema(schema, t('field.error')),
    [schema, t],
  );

  const form = useForm<InternalDomainCreateFormValues>({
    resolver: zodResolver(domainCreateSchema),
    defaultValues: {
      domain_url: '',
    },
    mode: 'onBlur',
  });

  const handleCreate = React.useCallback(
    async (values: InternalDomainCreateFormValues) => {
      if (!values.domain_url) return;
      await onCreate(values.domain_url);
      form.reset();
    },
    [form, onCreate],
  );

  const handleClose = React.useCallback(() => {
    form.reset();
    onClose();
  }, [form, onClose]);

  const onSubmit = React.useCallback(
    (e: React.FormEvent<HTMLFormElement>) => {
      e.preventDefault();
      form.handleSubmit(handleCreate)();
    },
    [form, handleCreate],
  );

  return (
    <Modal
      open={isOpen}
      onOpenChange={(open) => !open && handleClose()}
      className={cn('p-10', className)}
      title={t('title')}
      content={
        <div>
          <Form {...form}>
            <form id="domain-create-form" onSubmit={onSubmit}>
              <FormField
                control={form.control}
                name="domain_url"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel
                      htmlFor="domain-url"
                      className="text-sm text-(length:--font-size-label) font-medium"
                    >
                      {t('field.label')}
                    </FormLabel>
                    <FormControl>
                      <TextField
                        id="domain-url"
                        type="text"
                        placeholder={t('field.placeholder')}
                        className="mt-2"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </form>
          </Form>
        </div>
      }
      modalActions={{
        isLoading,
        nextAction: {
          type: 'button',
          label: t('actions.create_button_text'),
          variant: 'primary',
          disabled: isLoading,
          onClick: (e) => {
            e.preventDefault();
            form.handleSubmit(handleCreate)();
          },
        },
        previousAction: {
          label: t('actions.cancel_button_text'),
          onClick: handleClose,
        },
      }}
    />
  );
}

/**
 * Domain deletion confirmation modal.
 * @module domain-delete-modal
 * @internal
 */

import type { Domain } from '@auth0/universal-components-core';
import React from 'react';

import { Modal } from '@/components/ui/modal';
import { useTranslator } from '@/hooks/shared/use-translator';
import { cn } from '@/lib/utils';
import type { DomainDeleteModalProps } from '@/types/my-organization/domain-management/domain-delete-types';

const getDescriptionKey = (domain: Domain | null) => {
  return domain?.status === 'pending' ? 'description.pending' : 'description.verified';
};

/**
 *
 * @param props - Component props.
 * @param props.translatorKey - Translation namespace key
 * @param props.className - Optional CSS class name for styling
 * @param props.customMessages - Custom translation messages to override defaults
 * @param props.domain - Domain object or domain name
 * @param props.isOpen - Whether the modal/dialog is open
 * @param props.isLoading - Whether the component is in a loading state
 * @param props.onClose - Callback fired when the component should close
 * @param props.onDelete - Callback fired when delete action is triggered
 * @returns JSX element
 */
export function DomainDeleteModal({
  translatorKey = 'domain_management.domain_delete.modal',
  className,
  customMessages,
  domain,
  isOpen,
  isLoading,
  onClose,
  onDelete,
}: DomainDeleteModalProps) {
  const { t } = useTranslator(translatorKey, customMessages);

  const handleDelete = React.useCallback(() => {
    if (domain) {
      onDelete(domain);
    }
  }, [onDelete, domain]);

  return (
    <Modal
      open={isOpen}
      onOpenChange={(open) => !open && onClose()}
      className={cn('p-10', className)}
      title={t('title')}
      content={
        <div className={'space-y-6'}>
          <p className="text-sm text-muted-foreground text-(length:--font-size-paragraph)">
            {t(getDescriptionKey(domain), { domainName: domain?.domain })}
          </p>
        </div>
      }
      modalActions={{
        isLoading,
        nextAction: {
          type: 'button',
          label: t('actions.delete_button_text'),
          variant: 'destructive',
          disabled: isLoading,
          onClick: handleDelete,
        },
        previousAction: {
          label: t('actions.cancel_button_text'),
          onClick: onClose,
        },
      }}
    />
  );
}

/**
 * Domain verification modal.
 * @module domain-verify-modal
 * @internal
 */

import { MessageSquare } from 'lucide-react';
import React from 'react';

import { CopyableTextField } from '@/components/auth0/shared/copyable-text-field';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { Modal } from '@/components/ui/modal';
import { Spinner } from '@/components/ui/spinner';
import { useTranslator } from '@/hooks/shared/use-translator';
import { cn } from '@/lib/utils';
import type { DomainVerifyModalProps } from '@/types/my-organization/domain-management/domain-verify-types';

/**
 *
 * @param props - Component props.
 * @param props.translatorKey - Translation namespace key
 * @param props.className - Optional CSS class name for styling
 * @param props.customMessages - Custom translation messages to override defaults
 * @param props.isOpen - Whether the modal/dialog is open
 * @param props.isLoading - Whether the component is in a loading state
 * @param props.domain - Domain object or domain name
 * @param props.error - Error message or error object to display
 * @param props.onClose - Callback fired when the component should close
 * @param props.onVerify - Callback fired when verify action is triggered
 * @param props.onDelete - Callback fired when delete action is triggered
 * @returns JSX element
 */
export function DomainVerifyModal({
  translatorKey = 'domain_management.domain_verify.modal',
  className,
  customMessages,
  isOpen,
  isLoading,
  domain,
  error,
  onClose,
  onVerify,
  onDelete,
}: DomainVerifyModalProps) {
  const { t } = useTranslator(translatorKey, customMessages);

  const handleVerify = React.useCallback(() => {
    if (domain) {
      onVerify(domain);
    }
  }, [onVerify, domain]);

  const handleDelete = React.useCallback(() => {
    if (domain) {
      onDelete(domain);
    }
  }, [onDelete, domain]);

  return (
    <Modal
      open={isOpen}
      onOpenChange={(open) => !open && onClose()}
      className="p-10"
      title={t('title', { domainName: domain?.domain })}
      content={
        <div className={cn('space-y-4', className)}>
          {error && (
            <Alert variant="destructive">
              <MessageSquare className="h-4 w-4" />
              <AlertDescription className="text-destructive-foreground">{error}</AlertDescription>
            </Alert>
          )}

          <div className="space-y-2">
            <Label htmlFor="txt-record-name" className="text-sm font-medium">
              {t('txt_record_name.label')}
            </Label>
            <CopyableTextField
              id="txt-record-name"
              value={domain?.verification_host || ''}
              readOnly
              className="text-sm"
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="txt-record-content" className="text-sm font-medium">
              {t('txt_record_content.label')}
            </Label>
            <CopyableTextField
              id="txt-record-content"
              value={domain?.verification_txt || ''}
              readOnly
              className="text-sm"
            />
          </div>

          <div className="space-y-2 pt-4 border-t border-gray-200">
            <div className="flex items-center gap-2">
              <span className="text-sm text-foreground font-medium">
                {t('verification_status.label')}
              </span>
              <Badge variant="warning">{t('verification_status.pending')}</Badge>
            </div>
            <p className={'text-sm text-muted-foreground text-(length:--font-size-paragraph)'}>
              {t('verification_status.description')}
            </p>
          </div>

          <div className="flex gap-2 pt-2 -mb-4">
            <Button variant="outline" onClick={handleVerify} disabled={isLoading}>
              {isLoading ? <Spinner size="sm" /> : t('actions.verify_button_text')}
            </Button>
            <Button variant="destructive" onClick={handleDelete} disabled={isLoading}>
              {t('actions.delete_button_text')}
            </Button>
          </div>
        </div>
      }
      modalActions={{
        showNext: false,
        previousAction: {
          label: t('actions.done_button_text'),
          onClick: onClose,
          variant: 'primary',
        },
      }}
    />
  );
}

/**
 * ADFS SSO provider configuration form.
 * @module adfs-sso-configure-form
 * @internal
 */

import {
  createProviderConfigureSchema,
  type AdfsConfigureFormValues,
} from '@auth0/universal-components-core';
import { zodResolver } from '@hookform/resolvers/zod';
import * as React from 'react';
import { useState } from 'react';
import { useForm } from 'react-hook-form';

import { CommonConfigureFields } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-create/provider-configure/common-configure-fields';
import { CopyableTextField } from '@/components/auth0/shared/copyable-text-field';
import { FileUpload } from '@/components/ui/file-upload';
import {
  Form,
  FormField,
  FormItem,
  FormLabel,
  FormControl,
  FormMessage,
  FormDescription,
} from '@/components/ui/form';
import { Label } from '@/components/ui/label';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { TextField } from '@/components/ui/text-field';
import { useTranslator } from '@/hooks/shared/use-translator';
import { cn } from '@/lib/utils';
import type { ProviderConfigureFieldsProps } from '@/types/my-organization/idp-management/sso-provider/sso-provider-create-types';

export interface AdfsConfigureFormHandle {
  validate: () => Promise<boolean>;
  getData: () => AdfsConfigureFormValues;
  isDirty: () => boolean;
  reset: (data?: AdfsConfigureFormValues) => void;
}

interface AdfsConfigureFormProps extends Omit<ProviderConfigureFieldsProps, 'strategy'> {}

export const AdfsProviderForm = React.forwardRef<AdfsConfigureFormHandle, AdfsConfigureFormProps>(
  function AdfsProviderForm(
    { initialData, readOnly = false, customMessages = {}, className, onFormDirty, idpConfig },
    ref,
  ) {
    const { t } = useTranslator(
      'idp_management.create_sso_provider.provider_configure',
      customMessages,
    );

    const [uploadedFiles, setUploadedFiles] = useState<File[]>([]);

    const adfsData = initialData as AdfsConfigureFormValues | undefined;

    const form = useForm<AdfsConfigureFormValues>({
      resolver: zodResolver(createProviderConfigureSchema('adfs')),
      mode: 'onSubmit',
      reValidateMode: 'onChange',
      defaultValues: {
        meta_data_source: adfsData?.meta_data_source || 'meta_data_url',
        meta_data_location_url: adfsData?.meta_data_location_url || '',
        adfs_server: adfsData?.adfs_server || '',
        fedMetadataXml: adfsData?.fedMetadataXml || '',
      },
    });

    const { isDirty } = form.formState;

    React.useEffect(() => {
      onFormDirty?.(isDirty);
    }, [isDirty, onFormDirty]);

    React.useImperativeHandle(ref, () => ({
      validate: async () => {
        return await form.trigger();
      },
      getData: () => form.getValues(),
      isDirty: () => form.formState.isDirty,
      reset: (data) => {
        if (data) {
          form.reset(data);
        } else {
          form.reset();
        }
      },
    }));

    const typeValue = form.watch('meta_data_source');
    const showFederationMetadataFile = typeValue === 'meta_data_file';

    const handleFileUpload = async (files: File[]) => {
      setUploadedFiles(files);

      const file = files[0];
      if (file) {
        try {
          const content = await file.text();
          form.setValue('fedMetadataXml', content);
        } catch (error) {
          console.error('Error reading file:', error);
        }
      }
    };

    return (
      <Form {...form}>
        <div className={cn('space-y-6', className)}>
          <FormField
            control={form.control}
            name="meta_data_source"
            render={({ field }) => (
              <FormItem>
                <FormLabel className="text-sm font-medium text-(length:--font-size-label)">
                  {t('fields.adfs.meta_data_source.label')}
                </FormLabel>
                <FormControl>
                  <RadioGroup
