    const { coreClient } = useCoreClient();
    const { showCopyButtons } = useProviderFormMode(mode);

    const callbackUrl = React.useMemo(() => {
      const domain = coreClient?.getDomain() || 'YOUR_DOMAIN';
      return `https://${domain}/login/callback`;
