import * as React from 'react';

import { cn } from '@/lib/utils';

/**
 * Props for the `MiddleEllipsisText` component.
 */
export interface MiddleEllipsisTextProps {
  /**
   * Full text value to render and truncate from the middle when needed.
   */
  text: string;
  /**
   * Optional class names applied to the text container.
   */
  className?: string;
}

/**
 * Truncates text by preserving both the start and end segments and inserting
 * an ellipsis in the middle when the measured width exceeds the available width.
 *
 * @param text Full source text.
 * @param availableWidth Maximum width available for rendering in pixels.
 * @param font Canvas font shorthand used for text measurement.
 * @returns The display string and whether truncation was applied.
 */
function calculateTruncatedText(
  text: string,
  availableWidth: number,
  font: string,
): { truncated: string; isTruncated: boolean } {
  if (!text || availableWidth <= 0) {
    return { truncated: text, isTruncated: false };
  }

  // Create a canvas element for text measurement
  const canvas = document.createElement('canvas');
  const context = canvas.getContext('2d');
  if (!context) {
    return { truncated: text, isTruncated: false };
  }

  context.font = font;
  const ellipsis = '...';
  const fullWidth = context.measureText(text).width;

  // If text fits, return as-is
  if (fullWidth <= availableWidth) {
    return { truncated: text, isTruncated: false };
  }

  const ellipsisWidth = context.measureText(ellipsis).width;
  const targetWidth = availableWidth - ellipsisWidth;

  if (targetWidth <= 0) {
    return { truncated: ellipsis, isTruncated: true };
  }

  // Binary search for optimal split point
  let start = 0;
  let end = text.length;
  let bestStart = 0;
  let bestEnd = text.length;

  while (start <= end) {
    const mid = Math.floor((start + end) / 2);
    const leftPart = text.substring(0, mid);
    const rightPart = text.substring(text.length - mid);
    const combinedWidth =
      context.measureText(leftPart).width + context.measureText(rightPart).width;

    if (combinedWidth <= targetWidth) {
      bestStart = mid;
      bestEnd = text.length - mid;
      start = mid + 1;
    } else {
      end = mid - 1;
    }
  }

  const truncated = text.substring(0, bestStart) + ellipsis + text.substring(bestEnd);
  return { truncated, isTruncated: true };
}

/**
 * Renders text that truncates in the middle (`abc...xyz`) based on the
 * container width while preserving both the prefix and suffix.
 *
 * A tooltip with the original text is provided when truncation occurs.
 */
export const MiddleEllipsisText = React.memo(
  React.forwardRef<HTMLSpanElement, MiddleEllipsisTextProps>(({ text, className }, ref) => {
    const [displayText, setDisplayText] = React.useState(text);
    const [isTruncated, setIsTruncated] = React.useState(false);
    const containerRef = React.useRef<HTMLSpanElement>(null);
    const rafIdRef = React.useRef<number | null>(null);

    React.useImperativeHandle(ref, () => containerRef.current!);

    const updateTruncation = React.useCallback(() => {
      const container = containerRef.current;
      if (!container) return;

      const computedStyle = window.getComputedStyle(container);
      const font = `${computedStyle.fontSize} ${computedStyle.fontFamily}`;
      const availableWidth = container.offsetWidth;

      const { truncated, isTruncated: truncated_flag } = calculateTruncatedText(
        text,
        availableWidth,
        font,
      );

      setDisplayText(truncated);
      setIsTruncated(truncated_flag);
    }, [text]);

    // Update truncation on mount/text change and observe resize
    React.useEffect(() => {
      updateTruncation();

      const container = containerRef.current;
      let resizeObserver: ResizeObserver | null = null;

      if (container) {
        resizeObserver = new ResizeObserver(() => {
          if (rafIdRef.current !== null) {
            cancelAnimationFrame(rafIdRef.current);
          }
          rafIdRef.current = requestAnimationFrame(() => {
            updateTruncation();
          });
        });

        resizeObserver.observe(container);
      }

      return () => {
        if (rafIdRef.current !== null) {
          cancelAnimationFrame(rafIdRef.current);
          rafIdRef.current = null;
        }
        resizeObserver?.disconnect();
      };
    }, [updateTruncation]);

    return (
      <span
        ref={containerRef}
        className={cn('block min-w-0', className)}
        title={isTruncated ? text : undefined}
      >
        {displayText}
      </span>
    );
  }),
);

/**
 * Section layout with title and actions.
 * @module section
 * @internal
 */

import type { ActionButton as CoreActionButton } from '@auth0/universal-components-core';
import type { LucideIcon } from 'lucide-react';
import * as React from 'react';

import { Button } from '@/components/ui/button';
import { Toggle } from '@/components/ui/toggle';
import { cn } from '@/lib/utils';

export interface BaseActionProps extends Omit<CoreActionButton, 'icon' | 'onClick'> {
  icon?: LucideIcon;
  className?: string;
}

export interface ButtonActionProps extends BaseActionProps {
  type: 'button';
  onClick: (e: React.MouseEvent<HTMLButtonElement>) => void;
}

export interface ToggleActionProps extends Omit<BaseActionProps, 'type'> {
  type: 'toggle';
  pressed?: boolean;
  onPressedChange: (pressed: boolean) => void;
  'aria-label': string;
}

export type ActionProps = ButtonActionProps | ToggleActionProps;

interface SectionProps {
  title?: string;
  description?: string;
  children: React.ReactNode;
  actions?: ActionProps[];
  className?: string;
}

const ButtonAction: React.FC<ButtonActionProps> = ({
  icon: Icon,
  className,
  label,
  onClick,
  disabled,
  variant,
  size,
}) => (
  <Button
    onClick={onClick}
    disabled={disabled}
    variant={variant}
    size={size}
    className={cn('flex items-center gap-2 w-full sm:w-auto sm:min-w-fit', className)}
    aria-label={label}
  >
    {Icon && <Icon className="h-4 w-4 flex-shrink-0" aria-hidden="true" />}
    <span className="truncate">{label}</span>
  </Button>
);

const ToggleAction: React.FC<ToggleActionProps> = ({
  icon: Icon,
  className,
  label,
  'aria-label': ariaLabel,
  pressed,
  onPressedChange,
  disabled,
  variant,
  size,
}) => (
  <Toggle
    pressed={pressed}
    onPressedChange={onPressedChange}
    disabled={disabled}
    variant={variant === 'outline' ? 'outline' : 'default'}
    size={size === 'icon' || size === 'xs' ? 'sm' : size}
    className={cn('flex items-center gap-2', className)}
    aria-label={ariaLabel}
  >
    {Icon && <Icon className="h-4 w-4 flex-shrink-0" aria-hidden="true" />}
    {label && <span className="truncate">{label}</span>}
  </Toggle>
);

/**
 *
 * @param props - Component props.
 * @param props.title - The title text
 * @param props.description - The description text
 * @param props.children - Child elements to render
 * @param props.actions - Action buttons or elements
 * @param props.className - Optional CSS class name for styling
 * @returns JSX element
 */
export function Section({
  title,
  description,
  children,
  actions,
  className,
}: SectionProps): React.JSX.Element {
  const renderAction = (action: ActionProps, index: number) => {
    const key = `action-${index}`;
    return action.type === 'toggle' ? (
      <ToggleAction key={key} {...action} />
    ) : (
      <ButtonAction key={key} {...action} />
    );
  };

  return (
    <div className={cn('space-y-6', className)}>
      <div className="flex items-start justify-between gap-4">
        <div className="flex flex-col min-w-0 flex-1 space-y-2">
          {title && (
            <h3
              className={cn(
                'text-lg text-foreground text-(length:--font-size-subtitle) font-semibold mb-1 text-left',
              )}
            >
              {title}
            </h3>
          )}
          {description && (
            <p
              className={cn(
                'text-sm text-muted-foreground text-left text-(length:--font-size-paragraph)',
              )}
            >
              {description}
            </p>
          )}
        </div>

        {actions && actions.length > 0 && (
          <div className="flex-shrink-0 flex items-start gap-2 mt-1">
            {actions.map(renderAction)}
          </div>
        )}
      </div>

      <div className="space-y-6">{children}</div>
    </div>
  );
}

