/**
 * SSO domain tab data and actions hook.
 * @module use-sso-domain-tab
 */

import type { CreateOrganizationDomainRequestContent } from '@auth0/universal-components-core';
import {
  BusinessError,
  type Domain,
  type IdpId,
  MY_ORGANIZATION_DOMAIN_SCOPES,
} from '@auth0/universal-components-core';
import { useQuery, useQueryClient, useMutation, useQueries } from '@tanstack/react-query';
import { useCallback, useState, useMemo, useEffect } from 'react';

import { showToast } from '@/components/auth0/shared/toast';
import { useCoreClient } from '@/hooks/shared/use-core-client';
import { useErrorHandler } from '@/hooks/shared/use-error-handler';
import { useTranslator } from '@/hooks/shared/use-translator';
import type {
  UseSsoDomainTabOptions,
  UseSsoDomainTabReturn,
} from '@/types/my-organization/idp-management/sso-domain/sso-domain-tab-types';

const domainQueryKeys = {
  all: ['sso-domains'] as const,
  lists: () => [...domainQueryKeys.all, 'list'] as const,
  list: (idpId: IdpId) => [...domainQueryKeys.lists(), idpId] as const,
  idpAssociations: () => [...domainQueryKeys.all, 'idp-associations'] as const,
  idpAssociation: (domainId: string, idpId: IdpId) =>
    [...domainQueryKeys.idpAssociations(), domainId, idpId] as const,
};

/**
 * Hook for SSO domain tab domain operations and state.
 * @param idpId - Identity provider ID.
 * @param options - Hook options.
 * @param options.customMessages - Custom translation messages.
 * @param options.domains - Initial domains data.
 * @param options.provider - SSO provider data.
 * @returns Hook state and methods
 */
export function useSsoDomainTab(
  idpId: IdpId,
  { customMessages = {}, domains, provider }: Partial<UseSsoDomainTabOptions> = {},
): UseSsoDomainTabReturn {
  const { coreClient } = useCoreClient();
  const { t } = useTranslator('idp_management.notifications', customMessages);
  const { handleError } = useErrorHandler();
  const queryClient = useQueryClient();

  const [selectedDomain, setSelectedDomain] = useState<Domain | null>(null);
  const [showVerifyModal, setShowVerifyModal] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [verifyError, setVerifyError] = useState<string | undefined>(undefined);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [isUpdating, setIsUpdating] = useState(false);
  const [isUpdatingId, setIsUpdatingId] = useState<string | null>(null);

  // Fetch domains list using TanStack Query
  const domainsQuery = useQuery({
    queryKey: domainQueryKeys.list(idpId),
    queryFn: async () => {
      const response = await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_DOMAIN_SCOPES)
        .organization.domains.list();
      return response.organization_domains;
    },
    enabled: !!coreClient && !!idpId,
  });

  const domainsList = domainsQuery.data ?? [];
  const isLoading = domainsQuery.isLoading;

  // Handle errors from domains query
  useEffect(() => {
    if (domainsQuery.error) {
      handleError(domainsQuery.error, {
        fallbackMessage: t('general_error'),
      });
    }
  }, [domainsQuery.error, handleError, t]);

  // Fetch IDP associations for each domain using useQueries
  const idpAssociationQueries = useQueries({
    queries: domainsList.map((domain) => ({
      queryKey: domainQueryKeys.idpAssociation(domain.id, idpId),
      queryFn: async () => {
        const response = await coreClient!
          .getMyOrganizationApiClient()
          .withScopes(MY_ORGANIZATION_DOMAIN_SCOPES)
          .organization.domains.identityProviders.get(domain.id);

        const isIdpEnabled = response.identity_providers?.some((idp) => idp.id === idpId);
        return { domainId: domain.id, isEnabled: isIdpEnabled ?? false };
      },
      enabled: !!coreClient && !!idpId,
      staleTime: 5 * 60 * 1000, // 5 minutes
    })),
  });

  // Derive idpDomains from query results
  const idpDomains = useMemo(
    () =>
      idpAssociationQueries
        .filter((query) => query.data?.isEnabled)
        .map((query) => query.data!.domainId),
    [idpAssociationQueries],
  );

  // Mutations
  const createDomainMutation = useMutation({
    mutationFn: async (data: CreateOrganizationDomainRequestContent) => {
      if (domains?.createAction?.onBefore) {
        const canProceed = domains.createAction.onBefore(data as Domain);
        if (!canProceed) {
          throw new BusinessError({ message: t('domain_create.on_before') });
        }
      }

      const result: Domain = await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_DOMAIN_SCOPES)
        .organization.domains.create(data);

      domains?.createAction?.onAfter?.(result);

      return result;
    },
    onSuccess: (newDomain) => {
      queryClient.invalidateQueries({ queryKey: domainQueryKeys.list(idpId) });
      // Also invalidate the IDP association for the new domain
      queryClient.invalidateQueries({
        queryKey: domainQueryKeys.idpAssociation(newDomain.id, idpId),
      });
    },
  });

  const verifyDomainMutation = useMutation({
    mutationFn: async (domain: Domain) => {
      if (domains?.verifyAction?.onBefore) {
        const canProceed = domains.verifyAction.onBefore(domain);
        if (!canProceed) {
          throw new BusinessError({ message: t('domain_verify.on_before') });
        }
      }

      const updatedDomain = await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_DOMAIN_SCOPES)
        .organization.domains.verify.create(domain.id);

      if (domains?.verifyAction?.onAfter) {
        await domains.verifyAction.onAfter(domain);
      }

      return { updatedDomain, isVerified: updatedDomain.status === 'verified' };
    },
    onSuccess: ({ updatedDomain, isVerified }, domain) => {
      if (isVerified) {
        queryClient.setQueryData<Domain[]>(domainQueryKeys.list(idpId), (oldDomains) => {
          if (!oldDomains) return oldDomains;
          return oldDomains.map((d) => (d.id === domain.id ? { ...d, ...updatedDomain } : d));
        });
      }
    },
  });

  const deleteDomainMutation = useMutation({
    mutationFn: async (domain: Domain) => {
      if (!coreClient) {
        return domain;
      }

      if (domains?.deleteAction?.onBefore) {
        const canProceed = domains.deleteAction.onBefore(domain);
        if (!canProceed) {
          throw new BusinessError({ message: t('domain_delete.on_before') });
        }
      }

      await coreClient
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_DOMAIN_SCOPES)
        .organization.domains.delete(domain.id);

      if (domains?.deleteAction?.onAfter) {
        await domains.deleteAction.onAfter(domain);
      }

      return domain;
    },
    onSuccess: (domain) => {
      queryClient.invalidateQueries({ queryKey: domainQueryKeys.list(idpId) });
      // Also invalidate the IDP association for the deleted domain
      queryClient.invalidateQueries({
        queryKey: domainQueryKeys.idpAssociation(domain.id, idpId),
      });
    },
  });

  const associateToProviderMutation = useMutation({
    mutationFn: async (domain: Domain) => {
      if (domains?.associateToProviderAction?.onBefore) {
        const canProceed = domains.associateToProviderAction.onBefore(domain, provider);
        if (!canProceed) {
          throw new BusinessError({ message: t('domain_associate_provider.on_before') });
        }
      }

      await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_DOMAIN_SCOPES)
        .organization.identityProviders.domains.create(idpId, {
          domain: domain.domain,
        });

      if (domains?.associateToProviderAction?.onAfter) {
        await domains.associateToProviderAction.onAfter(domain, provider);
      }

      return domain;
    },
    onSuccess: (domain) => {
      // Invalidate the IDP association query for this domain
      queryClient.invalidateQueries({
        queryKey: domainQueryKeys.idpAssociation(domain.id, idpId),
      });
    },
  });

  const deleteFromProviderMutation = useMutation({
    mutationFn: async (domain: Domain) => {
      if (!provider) {
        return domain;
      }

      if (domains?.deleteFromProviderAction?.onBefore) {
        const canProceed = domains.deleteFromProviderAction.onBefore(domain, provider);
        if (!canProceed) {
          throw new BusinessError({ message: t('domain_delete_provider.on_before') });
        }
      }

      await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_DOMAIN_SCOPES)
        .organization.identityProviders.domains.delete(provider.id!, domain.domain);

      if (domains?.deleteFromProviderAction?.onAfter) {
        await domains.deleteFromProviderAction.onAfter(domain);
      }

      return domain;
    },
    onSuccess: (domain) => {
      // Invalidate the IDP association query for this domain
      queryClient.invalidateQueries({
        queryKey: domainQueryKeys.idpAssociation(domain.id, idpId),
      });
    },
  });

  const handleCreate = useCallback(
    async (domainUrl: string) => {
      try {
        const newDomain = await createDomainMutation.mutateAsync({ domain: domainUrl });

        showToast({
          type: 'success',
          message: t('domain_create.success', {
            domainName: newDomain?.domain,
          }),
        });

        setSelectedDomain(newDomain);
        setShowCreateModal(false);
        setShowVerifyModal(true);
      } catch (error) {
        handleError(error, {
          fallbackMessage: t('domain_create.error'),
        });
      }
    },
    [handleError, createDomainMutation, t],
  );

  const handleCloseVerifyModal = useCallback(() => {
    setShowVerifyModal(false);
    setVerifyError(undefined);
  }, []);

  const handleVerify = useCallback(
    async (domain: Domain) => {
      try {
        const { isVerified } = await verifyDomainMutation.mutateAsync(domain);
        if (isVerified) {
          setShowVerifyModal(false);

          showToast({
            type: 'success',
            message: t('domain_verify.success', {
              domainName: domain.domain,
            }),
          });

          await associateToProviderMutation.mutateAsync(domain);
        } else {
          setVerifyError(t('domain_verify.verification_failed', { domainName: domain.domain }));
        }
      } catch (error) {
        handleError(error, {
          fallbackMessage: t('domain_verify.verification_failed'),
        });
      }
    },
    [verifyDomainMutation, t, handleError, associateToProviderMutation],
  );

  const handleDeleteClick = useCallback((domain: Domain) => {
    setSelectedDomain(domain);
    setShowVerifyModal(false);
    setShowDeleteModal(true);
  }, []);

  const handleDelete = useCallback(
    async (domain: Domain) => {
      try {
        await deleteDomainMutation.mutateAsync(domain);

        showToast({
          type: 'success',
          message: t('domain_delete.success', {
            domainName: domain.domain,
          }),
        });

        setShowDeleteModal(false);
        setShowVerifyModal(false);
      } catch (error) {
        handleError(error, {
          fallbackMessage: t('domain_delete.error'),
        });
      }
    },
    [handleError, deleteDomainMutation, t],
  );

  const handleVerifyActionColumn = useCallback(
    async (domain: Domain) => {
      setIsUpdating(true);
      setIsUpdatingId(domain.id);

      try {
        const { isVerified } = await verifyDomainMutation.mutateAsync(domain);
        if (isVerified) {
          showToast({
            type: 'success',
            message: t('domain_verify.success', {
              domainName: domain.domain,
            }),
          });

          await associateToProviderMutation.mutateAsync(domain);
        } else {
          showToast({
            type: 'error',
            message: t('domain_verify.verification_failed', {
              domainName: domain.domain,
            }),
          });
        }
      } catch (error) {
        handleError(error, {
          fallbackMessage: t('domain_verify.verification_failed', { domainName: domain.domain }),
        });
      } finally {
        setIsUpdating(false);
        setIsUpdatingId(null);
      }
    },
    [verifyDomainMutation, t, handleError, associateToProviderMutation],
  );

  const handleToggleSwitch = useCallback(
    async (domain: Domain, newCheckedValue: boolean) => {
      setIsUpdating(true);
      setIsUpdatingId(domain.id);

      if (newCheckedValue) {
        try {
          await associateToProviderMutation.mutateAsync(domain);

          showToast({
            type: 'success',
            message: t('domain_associate_provider.success', {
              domain: domain.domain,
              idp: provider?.name,
            }),
          });
        } catch (error) {
          handleError(error, {
            fallbackMessage: t('general_error'),
          });
        } finally {
          setIsUpdating(false);
          setIsUpdatingId(null);
        }
      } else {
        try {
          await deleteFromProviderMutation.mutateAsync(domain);

          showToast({
            type: 'success',
            message: t('domain_delete_provider.success', {
              domain: domain.domain,
              idp: provider?.name,
            }),
          });
        } catch (error) {
          handleError(error, {
            fallbackMessage: t('general_error'),
          });
        } finally {
          setIsUpdating(false);
          setIsUpdatingId(null);
        }
      }
    },
    [associateToProviderMutation, t, provider, handleError, deleteFromProviderMutation],
  );

  return {
    isLoading,
    domainsList,
    isCreating: createDomainMutation.isPending,
    selectedDomain,
    showVerifyModal,
    showDeleteModal,
    isVerifying: verifyDomainMutation.isPending,
    verifyError,
    isDeleting: deleteDomainMutation.isPending,
    showCreateModal,
    handleCreate,
    handleCloseVerifyModal,
    handleVerify,
    handleDeleteClick,
    handleDelete,
    setShowCreateModal,
    setShowDeleteModal,
    idpDomains,
    handleVerifyActionColumn,
    isUpdating,
    isUpdatingId,
    handleToggleSwitch,
  };
}

/**
 * SSO provider edit logic hook.
 * @module use-sso-provider-edit-logic
 * @internal
 */

import { useCallback } from 'react';

import { useConfig } from '@/hooks/my-organization/use-config';
import { useIdpConfig } from '@/hooks/my-organization/use-idp-config';
import type {
  UseSsoProviderEditLogicResult,
  UseSsoProviderEditReturn,
} from '@/types/my-organization/idp-management/sso-provider/sso-provider-edit-types';

/**
 * Hook for SSO provider edit logic (e.g., handleToggleProvider).
 * @param ssoProviderEdit - SSO Provider Edit Prop
 * @internal
 * @returns Hook state and methods
 */
export function useSsoProviderEditLogic(
  ssoProviderEdit: UseSsoProviderEditReturn,
): UseSsoProviderEditLogicResult {
  const { shouldAllowDeletion, isLoadingConfig } = useConfig();
  const { idpConfig, isLoadingIdpConfig, isProvisioningEnabled, isProvisioningMethodEnabled } =
    useIdpConfig();

  const showProvisioningTab =
    isProvisioningEnabled(ssoProviderEdit.provider?.strategy) &&
    isProvisioningMethodEnabled(ssoProviderEdit.provider?.strategy);

  const handleToggleProvider = useCallback(
    async (enabled: boolean) => {
      if (!ssoProviderEdit.provider?.strategy) return;
      await ssoProviderEdit.updateProvider({
        strategy: ssoProviderEdit.provider.strategy,
        is_enabled: enabled,
      });
    },
    [ssoProviderEdit.provider?.strategy, ssoProviderEdit.updateProvider],
  );

  return {
    shouldAllowDeletion,
    isLoadingConfig,
    idpConfig,
    isLoadingIdpConfig,
    showProvisioningTab,
    handleToggleProvider,
  };
}

/**
 * SSO provider edit hook.
 * @module use-sso-provider-edit
 */

import {
  OrganizationDetailsFactory,
  OrganizationDetailsMappers,
  SsoProviderMappers,
  type IdentityProvider,
  type IdpId,
  type OrganizationPrivate,
  type UpdateIdentityProviderRequestContent,
  type CreateIdpProvisioningScimTokenRequestContent,
  type GetIdPProvisioningConfigResponseContent,
  getStatusCode,
  MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES,
} from '@auth0/universal-components-core';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useCallback, useEffect, useMemo, useRef } from 'react';

import { showToast } from '@/components/auth0/shared/toast';
import { useCoreClient } from '@/hooks/shared/use-core-client';
import { useTranslator } from '@/hooks/shared/use-translator';
import type {
  UseSsoProviderEditOptions,
  UseSsoProviderEditReturn,
} from '@/types/my-organization/idp-management/sso-provider/sso-provider-edit-types';

const ACTION_CANCELLED_ERROR = 'ACTION_CANCELLED';

const isActionCancelledError = (error: unknown): boolean => {
  return error instanceof Error && error.message === ACTION_CANCELLED_ERROR;
};

export const ssoProviderEditQueryKeys = {
  all: ['sso-providers'] as const,
  detail: (idpId: IdpId) => [...ssoProviderEditQueryKeys.all, 'detail', idpId] as const,
  organization: () => ['organization', 'details'] as const,
  provisioning: (idpId: IdpId) => [...ssoProviderEditQueryKeys.all, 'provisioning', idpId] as const,
  scimTokens: (idpId: IdpId) => [...ssoProviderEditQueryKeys.all, 'scim-tokens', idpId] as const,
};

/**
 * Hook for editing SSO provider settings and provisioning.
 * @param idpId - Identity provider ID.
 * @param options - Hook options.
 * @param options.sso - SSO action callbacks.
 * @param options.provisioning - Provisioning action callbacks.
 * @param options.customMessages - Custom translation messages.
 * @returns Hook state and methods
 */
export function useSsoProviderEdit(
  idpId: IdpId,
  { sso, provisioning, customMessages = {} }: Partial<UseSsoProviderEditOptions> = {},
): UseSsoProviderEditReturn {
  const { coreClient } = useCoreClient();
  const { t } = useTranslator('idp_management.notifications', customMessages);
  const queryClient = useQueryClient();
  const hasShownProviderError = useRef(false);
  const hasShownProvisioningError = useRef(false);
  const hasShownOrganizationError = useRef(false);

  /**
   * Provider query - fetches the identity provider details.
   * TanStack Query handles caching, loading states, and refetching.
   */
  const providerQuery = useQuery({
    queryKey: ssoProviderEditQueryKeys.detail(idpId),
    queryFn: async (): Promise<IdentityProvider> => {
      const response = await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
        .organization.identityProviders.get(idpId);
      return response;
    },
    enabled: !!coreClient && !!idpId,
  });

  /**
   * Organization query - fetches organization details.
   * Shared across the application, so it uses a common query key.
   */
  const organizationQuery = useQuery({
    queryKey: ssoProviderEditQueryKeys.organization(),
    queryFn: async (): Promise<OrganizationPrivate> => {
      const response = await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
        .organizationDetails.get();
      return OrganizationDetailsMappers.fromAPI(response);
    },
    enabled: !!coreClient,
    initialData: OrganizationDetailsFactory.create(),
  });

  /**
   * Provisioning config query - fetches provisioning configuration.
   * Returns null if provisioning is not configured (404).
   */
  const provisioningQuery = useQuery({
    queryKey: ssoProviderEditQueryKeys.provisioning(idpId),
    queryFn: async (): Promise<GetIdPProvisioningConfigResponseContent | null> => {
      try {
        const result = await coreClient!
          .getMyOrganizationApiClient()
          .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
          .organization.identityProviders.provisioning.get(idpId);
        return result;
      } catch (error) {
        const status = getStatusCode(error);
        if (status === 404) {
          return null;
        }
        throw error;
      }
    },
    enabled: !!coreClient && !!idpId,
  });

  useEffect(() => {
    if (providerQuery.isError && !hasShownProviderError.current) {
      showToast({
        type: 'error',
        message: t('general_error'),
      });
      hasShownProviderError.current = true;
    }

    if (!providerQuery.isError) {
      hasShownProviderError.current = false;
    }
  }, [providerQuery.isError, t]);

  useEffect(() => {
    if (organizationQuery.isError && !hasShownOrganizationError.current) {
      const errorMessage =
        organizationQuery.error instanceof Error
          ? t('general_error', { message: organizationQuery.error.message })
          : t('general_error');

      showToast({
        type: 'error',
        message: errorMessage,
      });
      hasShownOrganizationError.current = true;
    }

    if (!organizationQuery.isError) {
      hasShownOrganizationError.current = false;
    }
  }, [organizationQuery.error, organizationQuery.isError, t]);

  useEffect(() => {
    if (provisioningQuery.isError && !hasShownProvisioningError.current) {
      showToast({
        type: 'error',
        message: t('general_error'),
      });
      hasShownProvisioningError.current = true;
    }

    if (!provisioningQuery.isError) {
      hasShownProvisioningError.current = false;
    }
  }, [provisioningQuery.isError, t]);

  /**
   * Update provider mutation - updates SSO provider configuration.
   */
  const updateProviderMutation = useMutation({
    mutationFn: async (data: UpdateIdentityProviderRequestContent): Promise<IdentityProvider> => {
      const provider = providerQuery.data;
      if (!provider) {
        throw new Error('Provider not loaded');
      }

      if (sso?.updateAction?.onBefore) {
        const canProceed = sso.updateAction.onBefore(provider);
        if (!canProceed) {
          throw new Error(ACTION_CANCELLED_ERROR);
        }
      }

      const apiRequestData: UpdateIdentityProviderRequestContent = SsoProviderMappers.updateToAPI({
        strategy: provider.strategy,
        ...data,
      });

      const result = await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
        .organization.identityProviders.update(idpId, apiRequestData);

      return result;
    },
    onSuccess: async (result, _variables) => {
      const provider = providerQuery.data;

      showToast({
        type: 'success',
        message: t('update_success', { providerName: provider?.display_name }),
      });

      // Update cache with new data
      queryClient.setQueryData(ssoProviderEditQueryKeys.detail(idpId), result);

      if (sso?.updateAction?.onAfter && provider) {
        await sso.updateAction.onAfter(provider, result);
      }
    },
    onError: (error) => {
      if (isActionCancelledError(error)) {
        return;
      }
      showToast({
        type: 'error',
        message: t('general_error'),
      });
    },
  });

  /**
   * Create provisioning mutation - enables provisioning for the provider.
   */
  const createProvisioningMutation = useMutation({
    mutationFn: async (): Promise<GetIdPProvisioningConfigResponseContent> => {
      const provider = providerQuery.data;
      if (!provider) {
        throw new Error('Provider not loaded');
      }

      if (provisioning?.createAction?.onBefore) {
        const canProceed = provisioning.createAction.onBefore(provider);
        if (!canProceed) {
          throw new Error(ACTION_CANCELLED_ERROR);
        }
      }

      const result = await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
        .organization.identityProviders.provisioning.create(idpId);

      return result;
    },
    onSuccess: async (result) => {
      const provider = providerQuery.data;

      showToast({
        type: 'success',
        message: t('update_success', { providerName: provider?.display_name }),
      });

      // Invalidate queries to refetch fresh data
      await queryClient.invalidateQueries({
        queryKey: ssoProviderEditQueryKeys.detail(idpId),
      });
      queryClient.setQueryData(ssoProviderEditQueryKeys.provisioning(idpId), result);

      if (provisioning?.createAction?.onAfter && provider) {
        await provisioning.createAction.onAfter(provider, result);
      }
    },
    onError: (error) => {
      if (isActionCancelledError(error)) {
        return;
      }
      showToast({
        type: 'error',
        message: t('general_error'),
      });
    },
  });

  /**
   * Delete provisioning mutation - disables provisioning for the provider.
   */
  const deleteProvisioningMutation = useMutation({
    mutationFn: async (): Promise<void> => {
      const provider = providerQuery.data;
      if (!provider) {
        throw new Error('Provider not loaded');
      }

      if (provisioning?.deleteAction?.onBefore) {
        const canProceed = provisioning.deleteAction.onBefore(provider);
        if (!canProceed) {
          throw new Error(ACTION_CANCELLED_ERROR);
        }
      }

      await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
        .organization.identityProviders.provisioning.delete(idpId);
    },
    onSuccess: async () => {
      const provider = providerQuery.data;

      showToast({
        type: 'success',
        message: t('update_success', { providerName: provider?.display_name }),
      });

      // Update cache to reflect deleted provisioning
      queryClient.setQueryData(ssoProviderEditQueryKeys.provisioning(idpId), null);
      await queryClient.invalidateQueries({
        queryKey: ssoProviderEditQueryKeys.detail(idpId),
      });

      if (provisioning?.deleteAction?.onAfter && provider) {
        await provisioning.deleteAction.onAfter(provider);
      }
    },
    onError: (error) => {
      if (isActionCancelledError(error)) {
        return;
      }
      showToast({
        type: 'error',
        message: t('general_error'),
      });
    },
  });

  /**
   * Create SCIM token mutation - generates a new SCIM token for provisioning.
   */
  const createScimTokenMutation = useMutation({
    mutationFn: async (data: CreateIdpProvisioningScimTokenRequestContent) => {
      const provider = providerQuery.data;
      if (!provider) {
        throw new Error('Provider not loaded');
      }

      if (provisioning?.createScimTokenAction?.onBefore) {
        const canProceed = provisioning.createScimTokenAction.onBefore(provider);
        if (!canProceed) {
          throw new Error(ACTION_CANCELLED_ERROR);
        }
      }

      const result = await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
        .organization.identityProviders.provisioning.scimTokens.create(idpId, data);

      return result;
    },
    onSuccess: async (result) => {
      const provider = providerQuery.data;

      showToast({
        type: 'success',
        message: t('scim_token_create_success'),
      });

      // Invalidate SCIM tokens list to refetch
      await queryClient.invalidateQueries({
        queryKey: ssoProviderEditQueryKeys.scimTokens(idpId),
      });

      if (provisioning?.createScimTokenAction?.onAfter && provider) {
        await provisioning.createScimTokenAction.onAfter(provider, result);
      }
    },
    onError: (error) => {
      if (isActionCancelledError(error)) {
        return;
      }
      showToast({
        type: 'error',
        message: t('general_error'),
      });
    },
  });

  /**
   * Delete SCIM token mutation - removes a SCIM token.
   */
  const deleteScimTokenMutation = useMutation({
    mutationFn: async (idpScimTokenId: string): Promise<void> => {
      const provider = providerQuery.data;
      if (!provider) {
        throw new Error('Provider not loaded');
      }

      if (provisioning?.deleteScimTokenAction?.onBefore) {
        const canProceed = provisioning.deleteScimTokenAction.onBefore(provider);
        if (!canProceed) {
          throw new Error(ACTION_CANCELLED_ERROR);
        }
      }

      await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
        .organization.identityProviders.provisioning.scimTokens.delete(idpId, idpScimTokenId);
    },
    onSuccess: async () => {
      const provider = providerQuery.data;

      showToast({
        type: 'success',
        message: t('scim_token_delete_sucess'),
      });

      // Invalidate SCIM tokens list to refetch
      await queryClient.invalidateQueries({
        queryKey: ssoProviderEditQueryKeys.scimTokens(idpId),
      });

      if (provisioning?.deleteScimTokenAction?.onAfter && provider) {
        await provisioning.deleteScimTokenAction.onAfter(provider);
      }
    },
    onError: (error) => {
      if (isActionCancelledError(error)) {
        return;
      }
      showToast({
        type: 'error',
        message: t('general_error'),
      });
    },
  });

  /**
   * Delete provider mutation - completely deletes the provider.
   */
  const deleteProviderMutation = useMutation({
    mutationFn: async (): Promise<void> => {
      const provider = providerQuery.data;
      if (!provider?.id) {
        throw new Error('Provider not loaded or missing ID');
      }

      await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
        .organization.identityProviders.delete(provider.id);
    },
    onSuccess: async () => {
      const provider = providerQuery.data;

      showToast({
        type: 'success',
        message: t('delete_success', { providerName: provider?.display_name }),
      });

      // Remove all related queries from cache
      queryClient.removeQueries({
        queryKey: ssoProviderEditQueryKeys.detail(idpId),
      });
      queryClient.removeQueries({
        queryKey: ssoProviderEditQueryKeys.provisioning(idpId),
      });
      queryClient.removeQueries({
        queryKey: ssoProviderEditQueryKeys.scimTokens(idpId),
      });

      if (sso?.deleteAction?.onAfter && provider) {
        await sso.deleteAction.onAfter(provider);
      }
    },
    onError: () => {
      showToast({
        type: 'error',
        message: t('general_error'),
      });
    },
  });

  /**
   * Detach provider mutation - removes provider from organization but doesn't delete it.
   */
  const detachProviderMutation = useMutation({
    mutationFn: async (): Promise<void> => {
      const provider = providerQuery.data;
      if (!provider?.id) {
        throw new Error('Provider not loaded or missing ID');
      }

      if (sso?.deleteFromOrganizationAction?.onBefore) {
        const canProceed = sso.deleteFromOrganizationAction.onBefore(provider);
        if (!canProceed) {
          throw new Error(ACTION_CANCELLED_ERROR);
        }
      }

      // Ensure organization data is fresh before detaching
      await queryClient.ensureQueryData({
        queryKey: ssoProviderEditQueryKeys.organization(),
      });

      await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
        .organization.identityProviders.detach(provider.id);
    },
    onSuccess: async () => {
      const provider = providerQuery.data;
      const organization = organizationQuery.data;

      showToast({
        type: 'success',
        message: t('remove_success', {
          providerName: provider?.display_name,
          organizationName: organization?.display_name,
        }),
      });

      // Remove provider from cache
      queryClient.removeQueries({
        queryKey: ssoProviderEditQueryKeys.detail(idpId),
      });

      if (sso?.deleteFromOrganizationAction?.onAfter && provider) {
        await sso.deleteFromOrganizationAction.onAfter(provider);
      }
    },
    onError: (error) => {
      if (isActionCancelledError(error)) {
        return;
      }
      showToast({
        type: 'error',
        message: t('general_error'),
      });
    },
  });

  const fetchProvider = useCallback(async (): Promise<IdentityProvider | null> => {
    if (!coreClient || !idpId) {
      return null;
    }

    try {
      const data = await queryClient.ensureQueryData({
        queryKey: ssoProviderEditQueryKeys.detail(idpId),
        queryFn: async () => {
          const response = await coreClient
            .getMyOrganizationApiClient()
            .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
            .organization.identityProviders.get(idpId);
          return response;
        },
      });
      return data;
    } catch (error) {
      showToast({
        type: 'error',
        message: t('general_error'),
      });
      return null;
    }
  }, [coreClient, idpId, queryClient, t]);

  const fetchOrganizationDetails = useCallback(async (): Promise<void> => {
    if (!coreClient) {
      return;
    }

    await queryClient.getQueryData(ssoProviderEditQueryKeys.organization());
  }, [coreClient, queryClient]);

  const fetchProvisioning =
    useCallback(async (): Promise<GetIdPProvisioningConfigResponseContent | null> => {
      if (!coreClient || !idpId) {
        return null;
      }

      try {
        const data = await queryClient.fetchQuery({
          queryKey: ssoProviderEditQueryKeys.provisioning(idpId),
          queryFn: async () => {
            try {
              const result = await coreClient
                .getMyOrganizationApiClient()
                .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
                .organization.identityProviders.provisioning.get(idpId);
              return result;
            } catch (error) {
              const status = getStatusCode(error);
              if (status === 404) {
                return null;
              }
              throw error;
            }
          },
        });
        return data;
      } catch (error) {
        const status = getStatusCode(error);
        if (status !== 404) {
          showToast({
            type: 'error',
            message: t('general_error'),
          });
        }
        return null;
      }
    }, [coreClient, idpId, queryClient, t]);

  const updateProvider = useCallback(
    async (data: UpdateIdentityProviderRequestContent): Promise<void> => {
      const provider = providerQuery.data;
      if (!coreClient || !idpId || !provider) {
        return;
      }

      try {
        await updateProviderMutation.mutateAsync(data);
      } catch (error) {
        if (!isActionCancelledError(error)) {
          throw error;
        }
      }
    },
    [coreClient, idpId, providerQuery.data, updateProviderMutation],
  );

  const createProvisioning = useCallback(async (): Promise<void> => {
    const provider = providerQuery.data;
    if (!coreClient || !idpId || !provider) {
      return;
    }

    try {
      await createProvisioningMutation.mutateAsync();
    } catch (error) {
      if (!isActionCancelledError(error)) {
        throw error;
      }
    }
  }, [coreClient, createProvisioningMutation, idpId, providerQuery.data]);

  const deleteProvisioning = useCallback(async (): Promise<void> => {
    const provider = providerQuery.data;
    if (!coreClient || !idpId || !provider) {
      return;
    }

    try {
      await deleteProvisioningMutation.mutateAsync();
    } catch (error) {
      if (!isActionCancelledError(error)) {
        throw error;
      }
    }
  }, [coreClient, deleteProvisioningMutation, idpId, providerQuery.data]);

  /**
   * List SCIM tokens mutation - fetches SCIM tokens for provisioning.
   * Note: This uses imperative fetching rather than a query because tokens
   * are typically fetched on-demand and the response includes sensitive data
   * that shouldn't be automatically cached.
   */
  const listScimTokensMutation = useMutation({
    mutationFn: async () => {
      if (!coreClient || !idpId) {
        return null;
      }

      const result = await coreClient
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
        .organization.identityProviders.provisioning.scimTokens.list(idpId);
      return result;
    },
    onError: () => {
      showToast({
        type: 'error',
        message: t('general_error'),
      });
    },
  });

  const listScimTokens = useCallback(async () => {
    try {
      return await listScimTokensMutation.mutateAsync();
    } catch (error) {
      return null;
    }
  }, [listScimTokensMutation]);

  const createScimToken = useCallback(
    async (data: CreateIdpProvisioningScimTokenRequestContent) => {
      const provider = providerQuery.data;
      if (!coreClient || !idpId || !provider) {
        return undefined;
      }

      try {
        return await createScimTokenMutation.mutateAsync(data);
      } catch (error) {
        if (!isActionCancelledError(error)) {
          throw error;
        }
        return undefined;
      }
    },
    [coreClient, createScimTokenMutation, idpId, providerQuery.data],
  );

  const deleteScimToken = useCallback(
    async (idpScimTokenId: string): Promise<void> => {
      const provider = providerQuery.data;
      if (!coreClient || !idpId || !provider) {
        return;
      }

      try {
        await deleteScimTokenMutation.mutateAsync(idpScimTokenId);
      } catch (error) {
        if (!isActionCancelledError(error)) {
          throw error;
        }
      }
    },
    [coreClient, deleteScimTokenMutation, idpId, providerQuery.data],
  );

  const syncSsoAttributesMutation = useMutation({
    mutationFn: async () => {
      await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
        .organization.identityProviders.updateAttributes(idpId, {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ssoProviderEditQueryKeys.detail(idpId),
      });
      showToast({
        type: 'success',
        message: t('sso_attributes_sync_success'),
      });
    },
    onError: () => {
      showToast({
        type: 'error',
        message: t('general_error'),
      });
    },
  });

  const syncSsoAttributes = useCallback(async (): Promise<void> => {
    if (!coreClient || !idpId) {
      return;
    }

    await syncSsoAttributesMutation.mutateAsync();
  }, [coreClient, idpId, syncSsoAttributesMutation]);

  const syncProvisioningAttributesMutation = useMutation({
    mutationFn: async () => {
      await coreClient!
        .getMyOrganizationApiClient()
        .withScopes(MY_ORGANIZATION_SSO_PROVIDER_EDIT_SCOPES)
        .organization.identityProviders.provisioning.updateAttributes(idpId, {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ssoProviderEditQueryKeys.provisioning(idpId),
      });
      showToast({
        type: 'success',
        message: t('provisioning_attributes_sync_success'),
      });
    },
    onError: () => {
      showToast({
        type: 'error',
        message: t('general_error'),
      });
    },
  });

  const syncProvisioningAttributes = useCallback(async (): Promise<void> => {
    if (!coreClient || !idpId) {
      return;
    }

    await syncProvisioningAttributesMutation.mutateAsync();
  }, [coreClient, idpId, syncProvisioningAttributesMutation]);

  const onDeleteConfirm = useCallback(async (): Promise<void> => {
    const provider = providerQuery.data;
    if (!coreClient || !provider?.id) {
      return;
    }

    try {
      await deleteProviderMutation.mutateAsync();
    } catch (error) {
      if (!isActionCancelledError(error)) {
        throw error;
      }
    }
  }, [coreClient, deleteProviderMutation, providerQuery.data]);

  const onRemoveConfirm = useCallback(async (): Promise<void> => {
    const provider = providerQuery.data;
    if (!coreClient || !provider?.id) {
      return;
    }

    try {
      await detachProviderMutation.mutateAsync();
    } catch (error) {
      if (!isActionCancelledError(error)) {
        throw error;
      }
    }
  }, [coreClient, detachProviderMutation, providerQuery.data]);

  const hasSsoAttributeSyncWarning = useMemo(() => {
    const provider = providerQuery.data;
    const attributes = provider && 'attributes' in provider ? (provider.attributes ?? []) : [];
    return attributes.some((attr) => attr.is_extra || attr.is_missing);
  }, [providerQuery.data]);

  const hasProvisioningAttributeSyncWarning = useMemo(() => {
    const provisioningConfig = provisioningQuery.data;
    const attributes = provisioningConfig?.attributes ?? [];
    return attributes.some((attr) => attr.is_extra || attr.is_missing);
  }, [provisioningQuery.data]);

  return {
    // Data from TanStack Query - single source of truth
    provider: providerQuery.data ?? null,
    organization: organizationQuery.data ?? OrganizationDetailsFactory.create(),
    provisioningConfig: provisioningQuery.data ?? null,

    // Loading states - all derived from TanStack Query
    isLoading: providerQuery.isLoading || organizationQuery.isLoading,
    isUpdating: updateProviderMutation.isPending,
    isDeleting: deleteProviderMutation.isPending,
    isRemoving: detachProviderMutation.isPending,
    isProvisioningUpdating: createProvisioningMutation.isPending,
    isProvisioningDeleting: deleteProvisioningMutation.isPending,
    isProvisioningLoading: provisioningQuery.isLoading || provisioningQuery.isFetching,
    isScimTokensLoading: listScimTokensMutation.isPending,
    isScimTokenCreating: createScimTokenMutation.isPending,
    isScimTokenDeleting: deleteScimTokenMutation.isPending,
    isSsoAttributesSyncing: syncSsoAttributesMutation.isPending,
    isProvisioningAttributesSyncing: syncProvisioningAttributesMutation.isPending,

    // Warning states
    hasSsoAttributeSyncWarning,
    hasProvisioningAttributeSyncWarning,

    // Actions
    fetchProvider,
    fetchOrganizationDetails,
    fetchProvisioning,
    updateProvider,
    createProvisioning,
    deleteProvisioning,
    listScimTokens,
    createScimToken,
    deleteScimToken,
    syncSsoAttributes,
    syncProvisioningAttributes,
    onDeleteConfirm,
    onRemoveConfirm,
  };
}

/**
 * CoreClient initialization hook.
 * @module use-core-client-initialization
 * @internal
 */

import type {
  CoreClientInterface,
  AuthDetails,
  I18nInitOptions,
} from '@auth0/universal-components-core';
import { createCoreClient } from '@auth0/universal-components-core';
import * as React from 'react';

interface UseCoreClientInitializationProps {
  authDetails: AuthDetails;
  i18nOptions?: I18nInitOptions;
}

/**
 * @internal
 * @param props - Initialization props.
 * @returns The initialized CoreClient instance, or null while initializing.
 */
export const useCoreClientInitialization = ({
  authDetails,
  i18nOptions,
}: UseCoreClientInitializationProps): CoreClientInterface | null => {
  const { authProxyUrl } = authDetails;
  const [coreClient, setCoreClient] = React.useState<CoreClientInterface | null>(null);

  React.useEffect(() => {
    const initializeCoreClient = async () => {
      try {
        const initializedCoreClient = await createCoreClient(authDetails, i18nOptions);
        setCoreClient(initializedCoreClient);
      } catch (error) {
        console.error(error);
      }
    };
    initializeCoreClient();
  }, [authProxyUrl, i18nOptions]);

  return coreClient;
};

/**
 * CoreClient context and hook.
 * @module use-core-client
 */

import type { CoreClientInterface } from '@auth0/universal-components-core';
import * as React from 'react';

/** @internal */
const CoreClientContext = React.createContext<{
  coreClient: CoreClientInterface | null;
}>({
  coreClient: null,
});

/**
 * Hook to access CoreClient from context.
 * @returns CoreClient instance or null.
 * @throws If used outside Auth0ComponentProvider.
 */
export const useCoreClient = () => {
  const context = React.useContext(CoreClientContext);
  if (!context) {
    throw new Error('useCoreClient must be used within Auth0ComponentProvider');
  }
  return context;
};

export { CoreClientContext };

/**
 * Error handling hook with toast notifications.
 * @module use-error-handler
 */

import { hasApiErrorBody, isBusinessError } from '@auth0/universal-components-core';
import { useCallback } from 'react';

import { showToast } from '@/components/auth0/shared/toast';

interface ErrorHandlerOptions {
  fallbackMessage?: string;
  showToastNotification?: boolean;
}

/**
 * Hook for handling errors with optional toast notifications.
 * @returns Error handler function.
 */
export const useErrorHandler = () => {
  const handleError = useCallback((error: unknown, options: ErrorHandlerOptions = {}) => {
    const { fallbackMessage = 'An error occurred', showToastNotification = true } = options;

    // Extract error message from various error types
    let errorMessage: string;

    if (isBusinessError(error)) {
      errorMessage = error.message;
    } else if (hasApiErrorBody(error) && error.body?.detail) {
      errorMessage = error.body.detail;
    } else if (error instanceof Error) {
      errorMessage = error.message;
    } else if (typeof error === 'string') {
      errorMessage = error;
    } else {
      errorMessage = fallbackMessage;
    }

    if (showToastNotification) {
      showToast({
        type: 'error',
        message: errorMessage,
      });
    }

    return errorMessage;
  }, []);

  return { handleError };
};

