/**
 * RWA proxy provider for server-side auth.
 * @module proxy-provider
 */

'use client';

import * as React from 'react';

import { Toaster } from '@/components/auth0/shared/sonner';
import { Spinner } from '@/components/ui/spinner';
import { CoreClientContext } from '@/hooks/shared/use-core-client';
import { useCoreClientInitialization } from '@/hooks/shared/use-core-client-initialization';
import { useToastProvider } from '@/hooks/shared/use-toast-provider';
import { QueryProvider } from '@/providers/query-provider';
import { ThemeProvider } from '@/providers/theme-provider';
import type { Auth0ComponentProviderProps } from '@/types/auth-types';

/**
 * Auth0 provider for RWAs using backend proxy auth.
 * @param props - Provider configuration including i18n, authDetails, themeSettings, toastSettings, cacheConfig, loader, and children.
 * @returns Provider component tree
 */
export const Auth0ComponentProvider = ({
  i18n,
  authDetails,
  themeSettings = {
    theme: 'default',
    mode: 'light',
    variables: {
      common: {},
      light: {},
      dark: {},
    },
  },
  toastSettings,
  cacheConfig,
  loader,
  children,
}: Auth0ComponentProviderProps & { children: React.ReactNode }) => {
  const mergedToastSettings = useToastProvider(toastSettings);

  const memoizedAuthDetails = React.useMemo(
    () => ({
      ...authDetails,
      contextInterface: undefined,
    }),
    [authDetails],
  );

  const coreClient = useCoreClientInitialization({
    authDetails: memoizedAuthDetails,
    i18nOptions: i18n,
  });

  const coreClientValue = React.useMemo(
    () => ({
      coreClient,
    }),
    [coreClient],
  );

  const fallback = loader || (
    <div className="flex items-center justify-center min-h-[200px]">
      <Spinner />
    </div>
  );

  return (
    <ThemeProvider
      themeSettings={{
        mode: themeSettings.mode,
        variables: themeSettings.variables,
        loader,
        theme: themeSettings.theme,
      }}
    >
      {mergedToastSettings.provider === 'sonner' && (
        <Toaster
          position={mergedToastSettings.settings?.position || 'top-right'}
          closeButton={mergedToastSettings.settings?.closeButton ?? true}
          className="auth0-universal"
        />
      )}
      {coreClient ? (
        <CoreClientContext.Provider value={coreClientValue}>
          <QueryProvider cacheConfig={cacheConfig}>{children}</QueryProvider>
        </CoreClientContext.Provider>
      ) : (
        fallback
      )}
    </ThemeProvider>
  );
};

export default Auth0ComponentProvider;

/**
 * TanStack Query provider wrapper.
 * @module query-provider
 * @internal
 */

import {
  QueryClient,
  QueryClientProvider as TanStackQueryClientProvider,
} from '@tanstack/react-query';
import { useState, type ReactElement, type ReactNode } from 'react';

/** Query cache configuration. */
export interface QueryCacheConfig {
  enabled?: boolean;
  staleTime?: number;
  gcTime?: number;
  refetchOnWindowFocus?: boolean | 'always';
}

/** Default cache configuration. */
export const DEFAULT_CACHE_CONFIG: Readonly<Required<QueryCacheConfig>> = {
  enabled: true,
  staleTime: 2 * 60 * 1000,
  gcTime: 5 * 60 * 1000,
  refetchOnWindowFocus: false,
} as const;

const QUERY_RETRY_CONFIG = {
  maxRetries: 3,
  maxRetryDelay: 30_000,
  backoffMultiplier: 2,
} as const;

const MUTATION_RETRY_CONFIG = {
  maxRetries: 1,
} as const;

const DISABLED_CACHE_GC_TIME = 5 * 1000;

/**
 * Merges user config with defaults.
 * @param userConfig - User-provided cache config.
 * @returns The resolved cache configuration
 * @internal
 */
export function resolveCacheConfig(userConfig?: QueryCacheConfig): Required<QueryCacheConfig> {
  const merged: Required<QueryCacheConfig> = {
    ...DEFAULT_CACHE_CONFIG,
    ...userConfig,
  };

  if (!merged.enabled) {
    return {
      ...merged,
      staleTime: 0,
      gcTime: DISABLED_CACHE_GC_TIME,
    };
  }

  return merged;
}

/**
 * Creates a QueryClient with config.
 * @param cacheConfig - Cache configuration.
 * @returns The configured QueryClient instance
 * @internal
 */
function createQueryClient(cacheConfig: Required<QueryCacheConfig>): QueryClient {
  return new QueryClient({
    defaultOptions: {
      queries: {
        staleTime: cacheConfig.staleTime,
        gcTime: cacheConfig.gcTime,
        refetchOnWindowFocus: cacheConfig.refetchOnWindowFocus,
        retry: QUERY_RETRY_CONFIG.maxRetries,
        retryDelay: (attemptIndex: number) =>
          Math.min(
            1000 * QUERY_RETRY_CONFIG.backoffMultiplier ** attemptIndex,
            QUERY_RETRY_CONFIG.maxRetryDelay,
          ),
        refetchOnReconnect: true,
      },
      mutations: {
        retry: MUTATION_RETRY_CONFIG.maxRetries,
      },
    },
  });
}

/** Props for QueryProvider. */
export interface QueryProviderProps {
  children: ReactNode;
  /** Cache config, only read on mount. */
  cacheConfig?: QueryCacheConfig;
}

/**
 * Internal TanStack Query provider wrapper.
 * @param props - Component props.
 * @param props.children - Child components.
 * @param props.cacheConfig - Cache configuration.
 * @returns The context provider component
 * @internal
 */
export function QueryProvider({ children, cacheConfig }: QueryProviderProps): ReactElement {
  const [queryClient] = useState(() => createQueryClient(resolveCacheConfig(cacheConfig)));

  return <TanStackQueryClientProvider client={queryClient}>{children}</TanStackQueryClientProvider>;
}

/**
 * SPA provider using @auth0/auth0-react.
 * @module spa-provider
 */

'use client';

import { useAuth0 } from '@auth0/auth0-react';
import type { BasicAuth0ContextInterface } from '@auth0/universal-components-core';
import * as React from 'react';

import { Toaster } from '@/components/auth0/shared/sonner';
import { Spinner } from '@/components/ui/spinner';
import { CoreClientContext } from '@/hooks/shared/use-core-client';
import { useCoreClientInitialization } from '@/hooks/shared/use-core-client-initialization';
import { useToastProvider } from '@/hooks/shared/use-toast-provider';
import { QueryProvider } from '@/providers/query-provider';
import { ThemeProvider } from '@/providers/theme-provider';
import type { Auth0ComponentProviderProps } from '@/types/auth-types';

/**
 * Auth0 provider for SPAs. Wraps components with required contexts.
 * @param props - Provider configuration including i18n, authDetails, themeSettings, toastSettings, cacheConfig, loader, and children.
 * @returns Provider component tree
 */
export const Auth0ComponentProvider = ({
  i18n,
  authDetails,
  themeSettings = {
    theme: 'default',
    mode: 'light',
    variables: {
      common: {},
      light: {},
      dark: {},
    },
  },
  toastSettings,
  cacheConfig,
  loader,
  children,
}: Auth0ComponentProviderProps & { children: React.ReactNode }) => {
  const mergedToastSettings = useToastProvider(toastSettings);

  const auth0ReactContext = useAuth0();

  const auth0ContextInterface = React.useMemo(() => {
    if (auth0ReactContext && 'isAuthenticated' in auth0ReactContext) {
      return auth0ReactContext as BasicAuth0ContextInterface;
    }

    if (authDetails?.contextInterface) {
      return authDetails.contextInterface;
    }

    throw new Error(
      'Auth0ContextInterface is not available. Make sure you wrap your app with Auth0Provider from @auth0/auth0-react, or pass a contextInterface via authDetails.',
    );
  }, [auth0ReactContext, authDetails?.contextInterface]);

  const memoizedAuthDetails = React.useMemo(
    () => ({
      ...(authDetails || {}),
      contextInterface: auth0ContextInterface,
    }),
    [authDetails, auth0ContextInterface],
  );

  const coreClient = useCoreClientInitialization({
    authDetails: memoizedAuthDetails,
    i18nOptions: i18n,
  });

  const coreClientValue = React.useMemo(
    () => ({
      coreClient,
    }),
    [coreClient],
  );

  const fallback = loader || (
    <div className="flex items-center justify-center min-h-[200px]">
      <Spinner />
    </div>
  );

  return (
    <ThemeProvider
      themeSettings={{
        mode: themeSettings.mode,
        variables: themeSettings.variables,
        loader,
        theme: themeSettings.theme,
      }}
    >
      {mergedToastSettings.provider === 'sonner' && (
        <Toaster
          position={mergedToastSettings.settings?.position || 'top-right'}
          closeButton={mergedToastSettings.settings?.closeButton ?? true}
          className="auth0-universal"
        />
      )}
      {coreClient ? (
        <CoreClientContext.Provider value={coreClientValue}>
          <QueryProvider cacheConfig={cacheConfig}>{children}</QueryProvider>
        </CoreClientContext.Provider>
      ) : (
        fallback
      )}
    </ThemeProvider>
  );
};

export default Auth0ComponentProvider;

/**
 * Theme provider for styling configuration.
 * @module theme-provider
 * @internal
 */

'use client';

import { applyStyleOverrides, type StylingVariables } from '@auth0/universal-components-core';
import * as React from 'react';

import { PortalContext } from '@/providers/portal-context';
import type { ThemeContextValue, ThemeInput } from '@/types/theme-types';

/** Default empty style overrides. */
const defaultStyleOverrides: StylingVariables = { common: {}, light: {}, dark: {} };

/**
 * Theme context for accessing theme settings.
 * @internal
 * @returns The context provider component
 */
export const ThemeContext = React.createContext<ThemeContextValue>({
  isDarkMode: false,
  variables: defaultStyleOverrides,
  loader: null,
});

/**
 * Provides theme configuration to the component tree.
 * @param props - Component props.
 * @param props.themeSettings - Theme settings with mode, variables, and loader.
 * @param props.children - Child components.
 * @returns Theme provider.
 * @internal
 */
export const ThemeProvider: React.FC<{
  themeSettings?: ThemeInput;
  children: React.ReactNode;
}> = ({ themeSettings, children }) => {
  const { variables, loader, mode, theme } = React.useMemo(
    () => ({
      variables: themeSettings?.variables ?? defaultStyleOverrides,
      loader: themeSettings?.loader ?? null,
      mode: themeSettings?.mode,
      theme: themeSettings?.theme ?? 'default',
    }),
    [themeSettings],
  );

  const [portalContainer, setPortalContainer] = React.useState<HTMLElement | null>(null);

  React.useEffect(() => {
    applyStyleOverrides(variables, mode, theme);
  }, [variables, mode, theme]);

  return (
    <ThemeContext.Provider value={{ isDarkMode: mode === 'dark', theme, variables, loader }}>
      <PortalContext.Provider value={portalContainer}>
        {children}
        <div className="auth0-universal" data-theme={theme} ref={setPortalContainer} />
      </PortalContext.Provider>
    </ThemeContext.Provider>
  );
};

