/** Toast notification type. */
export type ToastType = 'success' | 'info' | 'warning' | 'error';

/** Toast position options. */
export type ToastPosition =
  | 'top-left'
  | 'top-right'
  | 'bottom-left'
  | 'bottom-right'
  | 'top-center'
  | 'bottom-center';

/** Custom toast method signature. */
export interface CustomToastMethod {
  (message: string): void;
}

/** Custom toast methods for overriding default behavior. */
export interface CustomToastMethods {
  success?: CustomToastMethod;
  error?: CustomToastMethod;
  warning?: CustomToastMethod;
  info?: CustomToastMethod;
  dismiss?: (toastId?: string) => void;
}

/** Sonner toast settings. */
export interface SonnerSettings {
  position?: ToastPosition;
  maxToasts?: number;
  duration?: number;
  dismissible?: boolean;
  closeButton?: boolean;
}

/** Toast provider configuration. */
export type ToastSettings =
  | { provider?: 'sonner'; settings?: SonnerSettings }
  | { provider: 'custom'; methods: CustomToastMethods };

/** Toast options for showToast. */
export interface ToastOptions {
  type: ToastType;
  message: string;
  className?: string;
  icon?: ReactNode;
  data?: ExternalToast;
}

/** Default toast settings. */
export const DEFAULT_TOAST_SETTINGS: ToastSettings = {
  provider: 'sonner',
  settings: {
    position: 'top-right',
    closeButton: true,
  },
} as const;

/**
 * Tailwind CSS utility functions.
 * @module utils
 * @internal
 */

import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

/**
 * Merges class names with Tailwind CSS conflict resolution.
 * @param inputs - Input values to process
 * @returns The merged class name string
 * @internal
 */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

/**
 * Domain management utility functions.
 * @module domain-management-utils
 * @internal
 */

import type { Domain } from '@/types/my-organization/domain-management/domain-table-types';

/**
 * Returns badge variant for domain status.
 * @param status - Current status
 * @returns The badge variant
 * @internal
 */
export function getStatusBadgeVariant(
  status: Domain['status'],
): 'success' | 'warning' | 'destructive' | 'outline' {
  switch (status) {
    case 'verified':
      return 'success';
    case 'pending':
      return 'warning';
    case 'failed':
      return 'destructive';
    default:
      return 'outline';
  }
}
